/**
 * Validates required user registration fields.
 *
 * @input struct   Raw registration input.
 * @return struct
 */
public struct function validateRegistration(required struct input) {
  var errors = [];

  if (!len(trim(arguments.input.email ?: ''))) {
    errors.append('Email is required.');
  }
  if (!len(trim(arguments.input.displayName ?: ''))) {
    errors.append('Display name is required.');
  }
  if (!len(trim(arguments.input.password ?: ''))) {
    errors.append('Password is required.');
  }

  return { isValid: !errors.len(), errors: errors };
}

