/**
 * Validates a string matches basic email format.
 *
 * @email string   Value to validate.
 * @return struct
 */
public struct function validateEmail(required string email) {
  var clean = trim(arguments.email);
  var isValid = len(clean) > 0 && reFind('^[^@\s]+@[^@\s]+\.[^@\s]+$', clean) > 0;
  return { isValid: isValid, value: clean, error: isValid ? '' : 'Invalid email format.' };
}

