// Wrong: isValid("email") without trim or empty-string guard; "  " passes isValid
public struct function validateEmail(required string email) {
    if (!isValid("email", arguments.email)) {
        return { valid: false, error: "Invalid email" };
    }
    return { valid: true };
}

