/**
 * Validates a page number is within bounds.
 *
 * @page numeric     Requested page number.
 * @maxPage numeric  Maximum allowed page.
 * @return struct
 */
public struct function validatePageRange(required numeric page, required numeric maxPage) {
  var isValid = arguments.page >= 1 && arguments.page <= arguments.maxPage;
  return {
    isValid: isValid,
    value: arguments.page,
    error: isValid ? '' : 'Page must be between 1 and ' & arguments.maxPage & '.'
  };
}

