/**
 * Validates that a bio does not exceed the maximum allowed length.
 *
 * @bio string   User bio text.
 * @return struct
 */
public struct function validateBioLength(required string bio) {
  var maxLen = 500;
  var clean = trim(arguments.bio);
  var isValid = len(clean) <= maxLen;
  return {
    isValid: isValid,
    value: clean,
    error: isValid ? '' : 'Bio must not exceed ' & maxLen & ' characters (currently ' & len(clean) & ').'
  };
}

