/**
 * Validates a date range is ordered correctly.
 *
 * @startDate date   Inclusive range start.
 * @endDate date     Inclusive range end.
 * @return struct
 */
public struct function validateDateRange(required date startDate, required date endDate) {
  var isValid = dateCompare(arguments.startDate, arguments.endDate) < 0;
  return {
    isValid: isValid,
    error: isValid ? '' : 'Start date must be before end date.'
  };
}

/**
 * Guards state-changing actions by verifying the CSRF token.
 *
 * @rc struct    Request collection.
 * @prc struct   Private request collection.
 * @return void
 * @throws application When CSRF token is missing or invalid.
 */
public void function before(required struct rc, required struct prc) {
  var action = arguments.rc.action ?: '';
  var mutatingActions = ['save', 'delete', 'update'];
  if (mutatingActions.contains(action)) {
    var token = arguments.rc.csrfToken ?: '';
    if (!len(token) || token != session.csrfToken) {
      throw(type='application', message='Invalid or missing CSRF token.');
    }
  }
}

