/**
 * Cleans user-supplied search input for safe use in application logic.
 *
 * @input string   Raw user input.
 * @return string
 */
public string function sanitizeSearchInput(required string input) {
  var trimmed = trim(arguments.input);
  var stripped = reReplace(trimmed, '[<>&;]', '', 'ALL');
  return left(stripped, 200);
}

/**
 * Validates an array of line items, collecting errors per index.
 *
 * @items array   Line item structs to validate.
 * @return struct
 */
public struct function validateLineItems(required array items) {
  var errors = [];

  arguments.items.each(function(required struct item, required numeric idx) {
    if (!structKeyExists(item, 'productId') || !isNumeric(item.productId)) {
      errors.append('Item ' & idx & ': productId is required and must be numeric.');
    }
    if (!structKeyExists(item, 'quantity') || val(item.quantity) < 1) {
      errors.append('Item ' & idx & ': quantity must be at least 1.');
    }
  });

  return { isValid: !errors.len(), errors: errors };
}

